export const mockBatchSellTradesErc20Erc20: BatchSellTradesResponse = {
  transactions: mockBatchSellErc20Erc20.flatMap(({ trade, approval }) =>
    [
      {
        ...(trade as TxData),
        type: BatchSellTransactionType.TRADE,
        maxFeePerGas: '0x154a94',
        maxPriorityFeePerGas: '0xf4241',
      } as const,
      approval
        ? ({
            ...(approval as TxData),
            type: BatchSellTransactionType.APPROVAL,
            maxFeePerGas: '0x2',
            maxPriorityFeePerGas: '0x1',
          } as const)
        : undefined,
    ].filter((tx) => tx !== undefined),
  ),
  fee: {
    amount: '100',
    asset: getNativeAssetForChainId(10),
  },
};

export const getTxMetasForBatch = ({
  batchId,
  is7702,
}: {
  batchId: `0x${string}`;
  is7702: boolean;
}): TransactionMeta[] => {
  let date = Date.now();

  if (is7702) {
    return [
      {
        batchId,
        id: date.toString(16),
        hash: `0x${date.toString(16)}hash`,
        time: date,
        status: TransactionStatus.submitted,
        type: TransactionType.batch,
        chainId: '0xa',
        batchTransactionsOptions: {
          disable7702: !is7702,
        },
        txParams: {
          from: '0xaccount1',
          to: '0xbridgeContract',
          value: '0x0',
          data: '0xdata',
          chainId: '0xa',
          gasLimit: '0x5208',
          authorizationList: [
            {
              address: '0xupgradeAddress',
              chainId: '0xa',
              nonce: '0x1',
              r: '0xr',
              s: '0xs',
              yParity: '0x1',
            },
          ],
        },
        delegationAddress: '0xdelegationAddress',
        nestedTransactions: mockBatchSellTradesErc20Erc20.transactions.map(
          ({ gasLimit, ...trade }) => ({
            ...trade,
            chainId: '0xa',
            gas: toHex(Number(gasLimit)),
            type:
              // eslint-disable-next-line no-nested-ternary
              trade.type === BatchSellTransactionType.TRADE
                ? TransactionType.swap
                : trade.type === BatchSellTransactionType.APPROVAL
                  ? TransactionType.swapApproval
                  : TransactionType.tokenMethodTransfer,
          }),
        ),
        networkClientId: 'test-network-client-id',
      } as const,
    ];
  }

  return mockBatchSellTradesErc20Erc20.transactions.map((trade) => {
    date += 1;
    return {
      batchId,
      id: date.toString(16),
      hash: `0x${date.toString(16)}hash`,
      time: date,
      status: TransactionStatus.submitted,
      type:
        // eslint-disable-next-line no-nested-ternary
        trade.type === BatchSellTransactionType.TRADE
          ? TransactionType.swap
          : trade.type === BatchSellTransactionType.APPROVAL
            ? TransactionType.swapApproval
            : TransactionType.tokenMethodTransfer,
      chainId: '0xa',
      batchTransactionsOptions: {
        disable7702: !is7702,
      },
      txParams: {
        ...trade,
        chainId: '0xa',
        gasLimit: '0x5208',
      },
      networkClientId: 'test-network-client-id',
    } as const;
  });
};

export const getHistoryItem = (
  params: Partial<BridgeHistoryItem>,
): BridgeHistoryItem => {
  const { isStxEnabled, batchSellData, txMetaId, quote, quoteIds, featureId } =
    params;

  return {
    account: '0xaccount1',
    actionId: undefined,
    batchId: '0xBatchId1',
    featureId,
    hasApprovalTx: true,
    isStxEnabled,
    initialDestAssetBalance: undefined,
    location: MetaMetricsSwapsEventSource.Unknown,
    originalTransactionId: txMetaId,
    slippagePercentage: 0,
    startTime: 1779922719705,
    targetContractAddress: undefined,
    txMetaId,
    approvalTxId: undefined,
    estimatedProcessingTimeInSeconds: 60,
    pricingData: {
      amountSent: '0',
      amountSentInUsd: '100',
      quotedGasAmount: undefined,
      quotedGasInUsd: undefined,
      quotedReturnInUsd: '101',
    },
    status: {
      srcChain: {
        chainId: 10,
        txHash: isStxEnabled ? undefined : `0x${txMetaId}hash`,
      },
      status: StatusTypes.PENDING,
    },
    batchSellData,
    quote: quote as Quote,
    quoteId: undefined,
    ...(quoteIds ? { quoteIds } : {}),
  };
};
